# setup_logistica.ps1 - Modulo 6 Logistica TMS
# Ejecutar desde: Descargas\START_ERP\START_ERP\

Write-Host "Instalando Modulo 6 - Logistica TMS..." -ForegroundColor Cyan

Write-Host "  src/modules/logistics/types/tms.types.ts" -ForegroundColor Yellow
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
$dir = Split-Path "src\modules\logistics\types\tms.types.ts" -Parent
if ($dir) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\modules\logistics\types\tms.types.ts", $text, [System.Text.Encoding]::UTF8)

